def solve(N):
    if not isinstance(N, int) or N < 0:
        raise ValueError("Input must be a non-negative integer.")

    primes = []
    for num in range(2, N + 1):
        is_prime = True
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                is_prime = False
                break
        if is_prime:
            primes.append(num)

    return primes
